def move_piece(self, start_x, start_y, end_x, end_y):
    piece = self.get_piece(start_x, start_y)
    if not piece:
        raise ValueError("No piece at starting position")

    if self.get_piece(end_x, end_y) is not None:
        raise ValueError("Destination already occupied")

    # Check for valid move
    dx, dy = abs(end_x - start_x), abs(end_y - start_y)
    if (dx != 1 or dy != 1) and (dx != 2 or dy != 2):
        raise ValueError("Invalid move")

    # Handle capturing
    if dx == 2:
        middle_x, middle_y = (start_x + end_x) // 2, (start_y + end_y) // 2
        if not self.get_piece(middle_x, middle_y) or self.get_piece(middle_x, middle_y).color == piece.color:
            raise ValueError("Invalid capture")
        self.board.board[middle_x][middle_y] = None

    # Move the piece
    self.board[end_x][end_y] = piece
    self.board[start_x][start_y] = None

    # King the piece if it reaches the opposite end of the board
    if (self.current_player == "black" and end_x == 0) or (self.current_player == "white" and end_x == 7):
        piece.make_king()
